{
  "name": "Smart RHK Generator",
  "description": "Aplikasi AI untuk menghasilkan laporan kinerja guru otomatis dari foto kegiatan.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TeacherProfile {
  nama: string;
  nip: string;
  unitKerja: string;
  kota: string;
}

export interface AnalysisResult {
  judul_terpilih: string;
  jenis_kegiatan: 'Intrakurikuler' | 'Kokurikuler' | 'Ekstrakurikuler';
  latar_belakang: string;
  deskripsi: string;
  nilai_karakter: string[];
}

export interface ReportData {
  image: string; // Base64
  profile: TeacherProfile;
  periode: string;
  analysis: AnalysisResult;
  tanggalLaporan: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DAFTAR_RHK } from "../constants";
import { AnalysisResult } from "../types";

export const analyzeImageWithGemini = async (
  apiKey: string,
  base64Image: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });

  const model = "gemini-2.5-flash"; // Best for vision + speed

  // Clean base64 string if it contains metadata
  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpg|jpeg|webp);base64,/, "");

  const rhkListString = DAFTAR_RHK.join("\n- ");

  const prompt = `
    Saya mengirimkan foto kegiatan guru di sekolah. Tugasmu adalah menganalisis foto tersebut secara visual.

    Langkah kerja:
    1. Analisis aktivitas yang terlihat.
    2. COCOKKAN aktivitas tersebut dengan SATU judul yang PALING RELEVAN dari daftar RHK berikut:

    DAFTAR RHK:
    - ${rhkListString}

    3. Tentukan apakah kegiatan tersebut termasuk Intrakurikuler, Kokurikuler, atau Ekstrakurikuler.
    4. Buat 2 kalimat latar belakang akademis yang relevan.
    5. Buat 1 paragraf narasi formal (Deskripsi) menceritakan apa yang terjadi di foto secara spesifik.
    6. Tentukan 3 nilai karakter (Profil Pelajar Pancasila) yang relevan.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            judul_terpilih: { type: Type.STRING, description: "Judul RHK yang dipilih dari daftar" },
            jenis_kegiatan: { type: Type.STRING, enum: ["Intrakurikuler", "Kokurikuler", "Ekstrakurikuler"] },
            latar_belakang: { type: Type.STRING, description: "2 kalimat latar belakang akademis" },
            deskripsi: { type: Type.STRING, description: "Narasi formal kegiatan" },
            nilai_karakter: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "3 nilai karakter relevan"
            }
          },
          required: ["judul_terpilih", "jenis_kegiatan", "latar_belakang", "deskripsi", "nilai_karakter"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as AnalysisResult;

    // Double check if the title is actually in our list (hallucination check)
    if (!DAFTAR_RHK.includes(result.judul_terpilih)) {
      // Fallback: If AI invents a title, try to find the closest match or keep it if it makes sense, 
      // but strictly speaking we asked to pick from list. 
      // For this app, we trust the JSON schema enforcement of Gemini 2.5 Flash mostly.
      console.warn("AI generated a title not strictly in the list:", result.judul_terpilih);
    }

    return result;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw new Error("Gagal menganalisis foto. Pastikan API Key benar dan koneksi internet stabil.");
  }
};

import React, { useState, useEffect } from 'react';
import { TeacherProfile } from '../types';

interface Props {
  initialProfile: TeacherProfile | null;
  onSave: (profile: TeacherProfile) => void;
}

export const ProfileForm: React.FC<Props> = ({ initialProfile, onSave }) => {
  const [formData, setFormData] = useState<TeacherProfile>({
    nama: '',
    nip: '',
    unitKerja: '',
    kota: '',
  });

  useEffect(() => {
    if (initialProfile) {
      setFormData(initialProfile);
    }
  }, [initialProfile]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  return (
    <div className="w-full max-w-md mx-auto bg-white p-6 rounded-2xl shadow-lg border border-gray-100">
      <h2 className="text-2xl font-bold text-gray-800 mb-6 text-center">Data Guru</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Nama Lengkap & Gelar</label>
          <input
            type="text"
            required
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            value={formData.nama}
            onChange={(e) => setFormData({ ...formData, nama: e.target.value })}
            placeholder="Contoh: Budi Santoso, S.Pd."
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">NIP (Opsional)</label>
          <input
            type="text"
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            value={formData.nip}
            onChange={(e) => setFormData({ ...formData, nip: e.target.value })}
            placeholder="19850101 201001 1 001"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Unit Kerja / Sekolah</label>
          <input
            type="text"
            required
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            value={formData.unitKerja}
            onChange={(e) => setFormData({ ...formData, unitKerja: e.target.value })}
            placeholder="SDN 01 Jakarta"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Kota / Kabupaten</label>
          <input
            type="text"
            required
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition"
            value={formData.kota}
            onChange={(e) => setFormData({ ...formData, kota: e.target.value })}
            placeholder="Jakarta Selatan"
          />
        </div>
        <button
          type="submit"
          className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3 rounded-lg shadow-md transition-all transform hover:scale-[1.02] mt-4"
        >
          Simpan & Lanjutkan
        </button>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ProfileForm } from './components/ProfileForm';
import { ReportView } from './components/ReportView';
import { TeacherProfile, AnalysisResult, ReportData } from './types';
import { analyzeImageWithGemini } from './services/geminiService';

const App: React.FC = () => {
  // State
  const [apiKey, setApiKey] = useState<string>('');
  const [showKeyInput, setShowKeyInput] = useState<boolean>(false);
  const [profile, setProfile] = useState<TeacherProfile | null>(null);
  const [reportData, setReportData] = useState<ReportData | null>(null);

  // Upload & Process State
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [periode, setPeriode] = useState<string>('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize from LocalStorage
  useEffect(() => {
    const savedProfile = localStorage.getItem('rhk_profile');
    const savedKey = localStorage.getItem('rhk_gemini_key');
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedKey) setApiKey(savedKey);

    // Set default periode
    const date = new Date();
    const semester = date.getMonth() < 6 ? 'Januari - Juni' : 'Juli - Desember';
    setPeriode(`${semester} ${date.getFullYear()}`);
  }, []);

  // Handlers
  const handleSaveProfile = (newProfile: TeacherProfile) => {
    setProfile(newProfile);
    localStorage.setItem('rhk_profile', JSON.stringify(newProfile));
  };

  const handleSaveKey = (key: string) => {
    setApiKey(key);
    localStorage.setItem('rhk_gemini_key', key);
    setShowKeyInput(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { // 5MB limit
        alert("Ukuran file terlalu besar (Maks 5MB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProcess = async () => {
    if (!apiKey) {
      setError("Silakan masukkan API Key Gemini terlebih dahulu di menu pengaturan.");
      setShowKeyInput(true);
      return;
    }
    if (!selectedImage) {
      setError("Silakan upload foto terlebih dahulu.");
      return;
    }
    if (!profile) {
      setError("Profil belum lengkap.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const result: AnalysisResult = await analyzeImageWithGemini(apiKey, selectedImage);

      const newReport: ReportData = {
        image: selectedImage,
        profile: profile,
        periode: periode,
        analysis: result,
        tanggalLaporan: new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })
      };

      setReportData(newReport);
    } catch (err: any) {
      setError(err.message || "Terjadi kesalahan saat memproses gambar.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const resetAll = () => {
    setReportData(null);
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // --- RENDER ---

  // 1. View: Report
  if (reportData) {
    return <ReportView data={reportData} onReset={resetAll} />;
  }

  // 2. View: Profile Setup (First Time)
  if (!profile) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center items-center p-4">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold text-blue-600 mb-2">Smart RHK</h1>
          <p className="text-gray-500">Setup profil Anda untuk memulai.</p>
        </div>
        <ProfileForm initialProfile={null} onSave={handleSaveProfile} />
      </div>
    );
  }

  // 3. View: Dashboard / Main
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col max-w-lg mx-auto shadow-2xl relative">
      {/* Header */}
      <header className="bg-white p-6 shadow-sm flex justify-between items-center z-10 sticky top-0">
        <div>
          <h1 className="text-xl font-bold text-gray-800">Smart RHK</h1>
          <p className="text-xs text-gray-500 truncate w-40">Halo, {profile.nama}</p>
        </div>
        <button 
          onClick={() => setShowKeyInput(true)}
          className="p-2 bg-gray-100 rounded-full hover:bg-gray-200 text-gray-600"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
        </button>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-6 flex flex-col gap-6">

        {/* Status Card */}
        <div className="bg-blue-50 border border-blue-100 p-4 rounded-xl">
          <label className="text-xs text-blue-600 font-bold uppercase tracking-wider block mb-1">Periode Laporan</label>
          <input 
            type="text" 
            value={periode}
            onChange={(e) => setPeriode(e.target.value)}
            className="w-full bg-transparent text-blue-900 font-semibold border-b border-blue-200 focus:border-blue-500 outline-none pb-1"
          />
        </div>

        {/* Upload Area */}
        <div 
          onClick={() => fileInputRef.current?.click()}
          className={`
            border-2 border-dashed rounded-2xl p-8 flex flex-col items-center justify-center text-center cursor-pointer transition-all aspect-square sm:aspect-video
            ${selectedImage ? 'border-green-400 bg-green-50' : 'border-gray-300 hover:border-blue-400 hover:bg-gray-50'}
          `}
        >
          {selectedImage ? (
            <div className="relative w-full h-full flex items-center justify-center overflow-hidden rounded-lg">
              <img src={selectedImage} alt="Preview" className="max-w-full max-h-full object-contain" />
              <div className="absolute bottom-2 bg-black/50 text-white px-3 py-1 rounded-full text-xs">Ketuk untuk ganti</div>
            </div>
          ) : (
            <>
              <div className="bg-blue-100 p-4 rounded-full text-blue-600 mb-4">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
              </div>
              <h3 className="font-bold text-gray-700">Upload Bukti Foto</h3>
              <p className="text-sm text-gray-500 mt-1">Ambil dari galeri atau kamera</p>
            </>
          )}
          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleFileChange} 
            accept="image/*" 
            className="hidden" 
          />
        </div>

        {/* Error Message */}
        {error && (
          <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm flex items-start gap-2 animate-pulse">
            <svg className="w-5 h-5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
            <span>{error}</span>
          </div>
        )}

      </main>

      {/* Footer Action */}
      <footer className="p-6 bg-white border-t sticky bottom-0 z-20">
        <button
          onClick={handleProcess}
          disabled={!selectedImage || isAnalyzing}
          className={`
            w-full py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-3 transition-all
            ${!selectedImage || isAnalyzing 
              ? 'bg-gray-300 text-gray-500 cursor-not-allowed' 
              : 'bg-blue-600 text-white hover:bg-blue-700 hover:scale-[1.02]'
            }
          `}
        >
          {isAnalyzing ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Sedang Menganalisis...
            </>
          ) : (
            <>
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
              Analisis & Buat Laporan
            </>
          )}
        </button>
      </footer>

      {/* Settings Modal (API Key) */}
      {showKeyInput && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-sm p-6">
            <h3 className="text-lg font-bold mb-4">Pengaturan Gemini API</h3>
            <p className="text-sm text-gray-500 mb-4">
              Aplikasi ini membutuhkan API Key dari Google Gemini untuk fitur analisis foto. Key disimpan lokal di browser Anda.
            </p>
            <input 
              type="password" 
              placeholder="Masukkan API Key (AIza...)" 
              className="w-full border p-3 rounded-lg mb-4"
              value={apiKey}
              onChange={(e) => setApiKey(e.target.value)}
            />
            <div className="flex gap-3">
              <button 
                onClick={() => setShowKeyInput(false)}
                className="flex-1 py-2 text-gray-600 font-semibold"
              >
                Batal
              </button>
              <button 
                onClick={() => handleSaveKey(apiKey)}
                className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-semibold"
              >
                Simpan
              </button>
            </div>
            <div className="mt-4 text-xs text-center text-gray-400">
              <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noreferrer" className="underline hover:text-blue-500">Dapatkan API Key di sini</a>
            </div>
            {/* Edit Profile Link */}
            <div className="mt-6 border-t pt-4 text-center">
              <button 
                onClick={() => { setProfile(null); setShowKeyInput(false); }}
                className="text-sm text-blue-600 font-semibold"
              >
                Edit Data Profil Guru
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ProfileForm } from './components/ProfileForm';
import { ReportView } from './components/ReportView';
import { TeacherProfile, AnalysisResult, ReportData } from './types';
import { analyzeImageWithGemini } from './services/geminiService';

const App: React.FC = () => {
  // State Initialization - Read directly from LocalStorage to avoid UI flash/reset
  const [apiKey, setApiKey] = useState<string>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('rhk_gemini_key') || '';
    }
    return '';
  });

  const [profile, setProfile] = useState<TeacherProfile | null>(() => {
    if (typeof window !== 'undefined') {
      const savedProfile = localStorage.getItem('rhk_profile');
      return savedProfile ? JSON.parse(savedProfile) : null;
    }
    return null;
  });

  // UI State
  const [showKeyInput, setShowKeyInput] = useState<boolean>(false);
  const [reportData, setReportData] = useState<ReportData | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [periode, setPeriode] = useState<string>(() => {
    const date = new Date();
    const semester = date.getMonth() < 6 ? 'Januari - Juni' : 'Juli - Desember';
    return `${semester} ${date.getFullYear()}`;
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handlers
  const handleSaveProfile = (newProfile: TeacherProfile) => {
    setProfile(newProfile);
    localStorage.setItem('rhk_profile', JSON.stringify(newProfile));
  };

  const handleSaveKey = (key: string) => {
    setApiKey(key);
    localStorage.setItem('rhk_gemini_key', key);
    setShowKeyInput(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { // 5MB limit
        alert("Ukuran file terlalu besar (Maks 5MB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProcess = async () => {
    if (!apiKey) {
      setError("Silakan masukkan API Key Gemini terlebih dahulu di menu pengaturan.");
      setShowKeyInput(true);
      return;
    }
    if (!selectedImage) {
      setError("Silakan upload foto terlebih dahulu.");
      return;
    }
    if (!profile) {
      setError("Profil belum lengkap.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const result: AnalysisResult = await analyzeImageWithGemini(apiKey, selectedImage);

      const newReport: ReportData = {
        image: selectedImage,
        profile: profile,
        periode: periode,
        analysis: result,
        tanggalLaporan: new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })
      };

      setReportData(newReport);
    } catch (err: any) {
      setError(err.message || "Terjadi kesalahan saat memproses gambar.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const resetAll = () => {
    setReportData(null);
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // --- RENDER ---

  // 1. View: Report
  if (reportData) {
    return <ReportView data={reportData} onReset={resetAll} />;
  }

  // 2. View: Profile Setup (First Time)
  if (!profile) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center items-center p-4">
        <div className="mb-8 text-center">
          <h1 className="text-3xl font-bold text-blue-600 mb-2">Smart RHK</h1>
          <p className="text-gray-500">Setup profil Anda untuk memulai.</p>
        </div>
        <ProfileForm initialProfile={null} onSave={handleSaveProfile} />
      </div>
    );
  }

  // 3. View: Dashboard / Main
  return (
