import React, { useState, useRef } from 'react';
import { ProfileForm } from './components/ProfileForm';
import { ReportView } from './components/ReportView';
import { TeacherProfile, AnalysisResult, ReportData } from './types';
import { analyzeImageWithGemini } from './services/geminiService';

const App: React.FC = () => {
  // --- ENVIRONMENT VARIABLE HANDLING ---
  // Mencoba berbagai variasi nama variabel environment yang umum digunakan oleh Netlify/Vite/CRA
  const API_KEY = (() => {
    try {
      // 1. Cek import.meta.env (Modern Vite)
      // @ts-ignore
      if (typeof import.meta !== 'undefined' && import.meta.env) {
        // @ts-ignore
        if (import.meta.env.VITE_API_KEY) return import.meta.env.VITE_API_KEY;
        // @ts-ignore
        if (import.meta.env.API_KEY) return import.meta.env.API_KEY;
      }

      // 2. Cek process.env (Standard Node/CRA/Webpack)
      if (typeof process !== 'undefined' && process.env) {
        if (process.env.REACT_APP_API_KEY) return process.env.REACT_APP_API_KEY;
        if (process.env.VITE_API_KEY) return process.env.VITE_API_KEY;
        if (process.env.API_KEY) return process.env.API_KEY;
      }
    } catch (e) {
      console.warn("Error reading environment variables", e);
    }
    return '';
  })();

  // --- STATE MANAGEMENT ---
  const [profile, setProfile] = useState<TeacherProfile | null>(() => {
    if (typeof window !== 'undefined') {
      const savedProfile = localStorage.getItem('rhk_profile');
      return savedProfile ? JSON.parse(savedProfile) : null;
    }
    return null;
  });

  const [reportData, setReportData] = useState<ReportData | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [periode, setPeriode] = useState<string>(() => {
    const date = new Date();
    const semester = date.getMonth() < 6 ? 'Januari - Juni' : 'Juli - Desember';
    return `${semester} ${date.getFullYear()}`;
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- HANDLERS ---

  const handleSaveProfile = (newProfile: TeacherProfile) => {
    setProfile(newProfile);
    localStorage.setItem('rhk_profile', JSON.stringify(newProfile));
  };

  const handleChangeProfile = () => {
    if (confirm("Apakah Anda ingin mengubah data profil guru?")) {
      setProfile(null);
      setReportData(null);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { 
        alert("Ukuran file terlalu besar (Maks 5MB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProcess = async () => {
    // Double check saat runtime (meskipun sudah di-handle di render)
    if (!API_KEY) {
      setError("Konfigurasi Error: API Key tidak ditemukan.");
      return;
    }
    if (!selectedImage) {
      setError("Silakan upload foto terlebih dahulu.");
      return;
    }
    if (!profile) {
      setError("Profil belum lengkap.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const result: AnalysisResult = await analyzeImageWithGemini(API_KEY, selectedImage);

      const newReport: ReportData = {
        image: selectedImage,
        profile: profile,
        periode: periode,
        analysis: result,
        tanggalLaporan: new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })
      };

      setReportData(newReport);
    } catch (err: any) {
      setError(err.message || "Terjadi kesalahan saat memproses gambar.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const resetAll = () => {
    setReportData(null);
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // --- RENDER ---

  // 0. VIEW: MISSING CONFIGURATION (BLOCKER)
  // Jika API Key tidak ditemukan sama sekali di environment, tampilkan panduan deploy.
  if (!API_KEY) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col justify-center items-center p-6 text-center">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-lg w-full border-t-4 border-red-500">
          <div className="w-16 h-16 bg-red-100 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
          </div>
          <h1 className="text-2xl font-bold text-slate-800 mb-2">API Key Tidak Terdeteksi</h1>
          <p className="text-slate-600 mb-6 leading-relaxed">
            Aplikasi berjalan di Netlify tetapi tidak dapat membaca <strong>Environment Variable</strong>.
          </p>

          <div className="bg-slate-100 p-4 rounded-xl text-left text-sm text-slate-700 mb-6">
            <p className="font-bold mb-2">Solusi Perbaikan di Netlify:</p>
            <ol className="list-decimal pl-5 space-y-2">
              <li>Buka Dashboard Netlify &gt; <strong>Site settings</strong>.</li>
              <li>Pilih menu <strong>Environment variables</strong>.</li>
              <li>Tambahkan variable baru dengan nama: <br/>
                <code className="bg-slate-200 px-1 py-0.5 rounded text-slate-900 font-mono font-bold">VITE_API_KEY</code>
              </li>
              <li>Isi value dengan kunci Gemini API Anda.</li>
              <li><strong>Trigger Redeploy</strong> (Deploy ulang) agar perubahan terbaca.</li>
            </ol>
          </div>

          <button 
            onClick={() => window.location.reload()}
            className="w-full py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-900 transition"
          >
            Saya Sudah Memperbaikinya, Refresh Halaman
          </button>
        </div>
      </div>
    );
  }

  // 1. VIEW: REPORT RESULT
  if (reportData) {
    return <ReportView data={reportData} onReset={resetAll} />;
  }

  // 2. VIEW: ONBOARDING / PROFILE SETUP
  if (!profile) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-teal-50 to-slate-100 flex flex-col justify-center items-center p-4">
        <div className="w-full max-w-md bg-white p-8 rounded-2xl shadow-xl">
          <div className="text-center mb-8">
            <div className="bg-teal-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-teal-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"></path></svg>
            </div>
            <h1 className="text-3xl font-bold text-slate-800 mb-2">Selamat Datang</h1>
            <p className="text-slate-500">Isi data diri Anda sekali saja untuk memulai membuat laporan otomatis.</p>
          </div>
          <ProfileForm initialProfile={null} onSave={handleSaveProfile} />
        </div>

        <div className="mt-8 text-center">
          <p className="text-xs text-slate-400 max-w-sm leading-relaxed mb-2">
            System Status: <span className="text-teal-600 font-bold">Online & Ready</span>
          </p>
        </div>
      </div>
    );
  }

  // 3. VIEW: MAIN DASHBOARD
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center pt-6 sm:pt-10 pb-6 px-4">
