import { GoogleGenAI, Type } from "@google/genai";
import { RHK_CATEGORIES } from "../constants";
import { AnalysisResult, CategoryId } from "../types";

export const analyzeImageWithGemini = async (
  apiKey: string,
  base64Image: string,
  categoryId: CategoryId
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const model = "gemini-2.5-flash"; 

  // Find the selected category configuration
  const selectedCategory = RHK_CATEGORIES.find(c => c.id === categoryId);
  if (!selectedCategory) throw new Error("Kategori RHK tidak valid");

  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpg|jpeg|webp);base64,/, "");
  const rhkListString = selectedCategory.rhkList.join("\n- ");

  // Contextual Prompt and Output Mapping based on Category
  let specificInstructions = "";

  if (categoryId === 'DIGITAL') {
    specificInstructions = `
      Fokus analisis: Pemanfaatan alat/media teknologi.
      Instruksi Output JSON:
      - 'latar_belakang': Jelaskan masalah pembelajaran konvensional atau kebutuhan digital yang melatarbelakangi kegiatan.
      - 'deskripsi': Jelaskan solusi teknologi yang digunakan, nama aplikasi/alat, dan cara guru menggunakannya.
      - 'nilai_karakter': Sebutkan 3 dampak efisiensi/efektivitas (contoh: "Meningkatkan literasi digital", "Pembelajaran lebih interaktif").
    `;
  } else if (categoryId === 'CHILD_FRIENDLY') {
    specificInstructions = `
      Fokus analisis: Interaksi humanis dan inklusif.
      Instruksi Output JSON:
      - 'latar_belakang': Jelaskan situasi awal siswa atau pentingnya menciptakan rasa aman/nyaman.
      - 'deskripsi': Jelaskan pendekatan "Ramah Anak" yang dilakukan guru (Sapaan, Metode Inklusif, Anti-bullying).
      - 'nilai_karakter': Sebutkan 3 respon positif siswa (contoh: "Siswa merasa dihargai", "Antusiasme meningkat").
    `;
  } else if (categoryId === 'RELIGIOUS_MODERATION') {
    specificInstructions = `
      Fokus analisis: Nilai kebangsaan dan toleransi.
      Instruksi Output JSON:
      - 'latar_belakang': Jelaskan konteks keberagaman atau pentingnya penanaman nilai moderasi di kelas.
      - 'deskripsi': Jelaskan aktivitas inti yang menanamkan nilai Tasamuh (Toleransi), Tawazun (Seimbang), atau Hubbul Wathon (Cinta Tanah Air).
      - 'nilai_karakter': Sebutkan 3 nilai indikator moderasi beragama yang muncul.
    `;
  } else {
    // Teaching (Default)
    specificInstructions = `
      Fokus analisis: Pedagogi guru.
      Instruksi Output JSON:
      - 'latar_belakang': Alasan akademis mengapa kegiatan ini dilakukan.
      - 'deskripsi': Narasi jalannya kegiatan pembelajaran.
      - 'nilai_karakter': 3 Profil Pelajar Pancasila yang muncul.
    `;
  }

  const prompt = `
    Saya mengirimkan foto kegiatan guru. Konteks: ${selectedCategory.title}.

    ${specificInstructions}

    Langkah kerja umum:
    1. Identifikasi visual foto.
    2. Pilih SATU Judul RHK yang paling cocok dari daftar:
    ${rhkListString}

    3. Isi JSON sesuai instruksi khusus di atas. Gunakan Bahasa Indonesia formal untuk laporan resmi dinas.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            judul_terpilih: { type: Type.STRING, description: "Judul dari daftar RHK" },
            jenis_kegiatan: { type: Type.STRING, enum: ["Intrakurikuler", "Kokurikuler", "Ekstrakurikuler"] },
            latar_belakang: { type: Type.STRING },
            deskripsi: { type: Type.STRING },
            nilai_karakter: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["judul_terpilih", "jenis_kegiatan", "latar_belakang", "deskripsi", "nilai_karakter"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as AnalysisResult;
    return result;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw new Error("Gagal menganalisis foto. Pastikan API Key benar dan koneksi internet stabil.");
  }
};

