    const cellPaddingClass = isSuperDense ? 'py-[1px] px-1' : isVeryDense ? 'py-0.5 px-2' : isDense ? 'py-1 px-2' : 'py-2 px-4';
    const headerPaddingClass = isSuperDense ? 'py-1 px-1' : isVeryDense ? 'py-1 px-2' : 'py-2 px-4';

    return (
      <div className="w-full">
         <div className="mb-1">
            <h3 className="text-center font-bold text-sm uppercase mb-0 leading-tight">{analysis.prinsipModerasi || 'Nilai Sikap'}</h3>
            <p className="text-center text-[10px] text-gray-600 italic">"{analysis.caption}"</p>
         </div>

         <div className="overflow-hidden border border-gray-300 rounded-sm">
           <table className={`min-w-full`}>
             <thead className={`bg-amber-100 ${rowFontSize}`}>
               <tr>
                 <th className={`${headerPaddingClass} border-b border-r border-gray-300 w-8 text-center`}>No</th>
                 <th className={`${headerPaddingClass} border-b border-r border-gray-300 text-left`}>Nama Siswa</th>
                 <th className={`${headerPaddingClass} border-b border-r border-gray-300 text-center w-12`}>Nilai</th>
                 <th className={`${headerPaddingClass} border-b border-gray-300 text-left`}>Deskripsi Sikap</th>
               </tr>
             </thead>
             <tbody className={rowFontSize}>
               {analysis.studentGrades.map((student, idx) => (
                 <tr key={idx} className={idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
                   <td className={`${cellPaddingClass} border-b border-r border-gray-200 text-center`}>{idx + 1}</td>
                   <td className={`${cellPaddingClass} border-b border-r border-gray-200 font-medium whitespace-nowrap`}>{student.nama}</td>
                   <td className={`${cellPaddingClass} border-b border-r border-gray-200 text-center font-bold 
                      ${student.predikat === 'SB' ? 'text-blue-600' : 
                        student.predikat === 'B' ? 'text-green-600' : 
                        student.predikat === 'C' ? 'text-amber-600' : 'text-red-600'}`}>
                     {student.predikat}
                   </td>
                   <td className={`${cellPaddingClass} border-b border-gray-200 text-gray-600 italic ${descFontSize}`}>
                     {student.deskripsi}
                   </td>
                 </tr>
               ))}
             </tbody>
           </table>
         </div>

         <div className="mt-1 text-[9px] text-gray-500">
           <p><span className="font-bold">Ket:</span> SB=Sangat Baik, B=Baik, C=Cukup, K=Kurang</p>
         </div>
      </div>
    );
  };

  // IF CATEGORY IS STUDENT ASSESSMENT, RENDER SPECIAL VIEW (SINGLE PAGE PREFERRED)
  if (categoryId === 'STUDENT_ASSESSMENT') {
     return (
       <div className="flex flex-col items-center w-full bg-gray-100 min-h-screen p-4 sm:p-8 print:p-0 print:bg-white print:block">
          {/* Floating Action Bar (Hidden when printing) */}
          <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 flex gap-4 bg-white px-6 py-3 rounded-full shadow-xl border border-gray-200 z-50 print:hidden transition-transform hover:-translate-y-1">
            <button
              onClick={() => window.print()}
              className="flex items-center gap-2 text-blue-600 font-semibold hover:text-blue-800"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
              Cetak PDF
            </button>
            <div className="w-px bg-gray-300"></div>
            <button
              onClick={onReset}
              className="flex items-center gap-2 text-red-600 font-semibold hover:text-red-800"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
              Buat Baru
            </button>
          </div>

          {/* 
            KEY CHANGE: Padding reduced to 10mm (p-[10mm]) 
            to allow more content on one page. 
          */}
          <div className={`sheet bg-white shadow-2xl print:shadow-none w-full max-w-[210mm] min-h-[297mm] p-[10mm] relative mx-auto print:mt-0 flex flex-col`}>
             {/* Header Assessment: Reduced margins */}
             <div className="text-center border-b-4 border-double border-amber-600 pb-1 mb-2">
                <h1 className="text-base font-bold uppercase text-gray-900 tracking-wide leading-tight">Jurnal Penilaian Sikap Sosial & Spiritual</h1>
                <h2 className="text-sm font-bold text-amber-700 leading-tight">Penguatan Moderasi Beragama</h2>
                <div className="flex justify-between mt-1 text-[10px] font-semibold border-t border-dashed border-amber-200 pt-1 px-2">
                   <span>Unit Kerja: {profile.unitKerja}</span>
                   <span>Periode: {periode}</span>
                </div>
             </div>

             {/* Content: Table */}
             <div className="flex-1">
                {renderAssessmentTable()}
             </div>

             {/* Footer Signature: Reduced margins */}
             <div className="mt-2 flex justify-end shrink-0 break-inside-avoid-page">
                <div className="text-center w-48">
                  <p className="text-xs">{profile.kota}, {tanggalLaporan}</p>
                  <p className="mt-0.5 mb-0 text-xs">Guru Mapel/Kelas,</p>

                  <div className="h-14 flex items-center justify-center my-0.5">
                    <img 
                      src="https://drive.google.com/thumbnail?id=1gdxnC3M_VZLA--WQ5eEB66EJAO7dYm3o&sz=w500" 
                      alt="Tanda Tangan" 
                      className="h-full object-contain mix-blend-multiply" 
                    />
                  </div>

                  <p className="font-bold underline text-sm">{profile.nama}</p>
                  <p className="text-xs">NIP. {profile.nip || "-"}</p>
                </div>
              </div>
          </div>
       </div>
     );
  }

  // --- STANDARD REPORT VIEW (FOR OTHER CATEGORIES) ---
  return (
    // Wrapper print settings
    <div className="flex flex-col items-center w-full bg-gray-100 min-h-screen p-4 sm:p-8 print:p-0 print:bg-white print:block">

      {/* Floating Action Bar (Hidden when printing) */}
      <div className="fixed bottom-6 left-1/2 transform -translate-x-1/2 flex gap-4 bg-white px-6 py-3 rounded-full shadow-xl border border-gray-200 z-50 print:hidden transition-transform hover:-translate-y-1">
        <button
          onClick={() => window.print()}
          className="flex items-center gap-2 text-blue-600 font-semibold hover:text-blue-800"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
          Cetak / PDF
        </button>
        <div className="w-px bg-gray-300"></div>
        <button
          onClick={onReset}
          className="flex items-center gap-2 text-red-600 font-semibold hover:text-red-800"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
          Buat Baru
        </button>
      </div>

      {/* --- HALAMAN 1: COVER --- */}
      <div className={`sheet shadow-2xl print:shadow-none w-full max-w-[210mm] min-h-[297mm] p-[25mm] mb-8 print:mb-0 relative mx-auto flex flex-col justify-between overflow-hidden ${theme?.bgGradient || 'bg-white'}`}>

        {/* Decorative Background Patterns (Theme Based) */}
        {theme && (
          <>
            <div className="absolute top-0 right-0 w-[500px] h-[500px] opacity-[0.07] pointer-events-none transform translate-x-1/4 -translate-y-1/4 rotate-12 print:opacity-[0.05]">
               <svg viewBox="0 0 24 24" fill="currentColor" className={`w-full h-full ${theme.primary}`}>
                  <path d={theme.patternPath} />
               </svg>
            </div>
            <div className="absolute bottom-0 left-0 w-[400px] h-[400px] opacity-[0.07] pointer-events-none transform -translate-x-1/4 translate-y-1/4 -rotate-12 print:opacity-[0.05]">
               <svg viewBox="0 0 24 24" fill="currentColor" className={`w-full h-full ${theme.primary}`}>
                  <path d={theme.patternPath} />
               </svg>
            </div>
          </>
        )}

        {/* Dynamic Border Applied Here */}
        <div className={`flex-1 flex flex-col items-center justify-between text-center p-8 ${activeBorderStyle} relative z-10 bg-white/40 backdrop-blur-sm print:bg-transparent`}>

          <div className="mt-10">
            <h1 className={`text-2xl font-serif font-bold tracking-widest uppercase mb-4 leading-relaxed px-4 whitespace-pre-line ${theme?.primary || 'text-slate-900'}`}>
              {categoryLabel || "Laporan Kinerja Guru"}
            </h1>
            <h2 className={`text-xl font-serif font-bold uppercase px-4 mt-6 ${theme ? `text-${colorName}-700` : 'text-gray-700'}`}>
              {analysis.judul_terpilih}
            </h2>
          </div>

          <div className="my-8 flex flex-col items-center">
            <img 
              src="https://upload.wikimedia.org/wikipedia/commons/9/9a/Kementerian_Agama_new_logo.png" 
              alt="Logo Kementerian Agama" 
              className="w-32 h-auto mb-6 object-contain"
            />
            <p className={`text-lg font-semibold uppercase tracking-wider ${theme ? `text-${colorName}-600` : 'text-gray-600'}`}>
              Periode: {periode}
            </p>
          </div>

          <div className="mb-10 w-full">
            <p className="text-sm uppercase tracking-widest text-gray-500 mb-4">Disusun Oleh:</p>
            <h3 className={`text-xl font-bold border-b-2 pb-2 inline-block min-w-[50%] ${theme ? `text-slate-900 border-${colorName}-800` : 'text-slate-900 border-gray-800'}`}>
              {profile.nama}
            </h3>
            <p className="text-lg mt-2 font-mono">{profile.nip ? `NIP. ${profile.nip}` : '-'}</p>
          </div>

          <div className="w-full mb-4">
            <h4 className="text-xl font-bold uppercase">{profile.unitKerja}</h4>
            <p className={`text-md uppercase ${theme ? `text-${colorName}-700` : 'text-gray-600'}`}>{profile.kota}</p>
            <p className="text-sm text-gray-500 mt-2">2025</p>
          </div>
        </div>
      </div>

      {/* --- HALAMAN 2: ISI LAPORAN (DYNAMIC) --- */}
      <div className="sheet bg-white shadow-2xl print:shadow-none w-full max-w-[210mm] min-h-[297mm] p-[25mm] relative mx-auto print:mt-0 mb-8 print:mb-0 flex flex-col">
        <div className="font-serif text-justify leading-relaxed text-gray-900 h-full flex flex-col">

          {/* Header Internal */}
          <div className="border-b-2 border-gray-800 pb-4 mb-6 text-center shrink-0">
            <h2 className="text-lg font-bold uppercase">Laporan Pelaksanaan Kinerja</h2>
            <p className="text-sm text-gray-600">{analysis.jenis_kegiatan}</p>
          </div>

          {/* Body Content */}
          {renderDynamicContent()}

          {/* Footer Note */}
          <div className="mt-auto text-right text-xs italic text-gray-400">
            (Dokumentasi dan Pengesahan di halaman berikutnya)
          </div>
        </div>
      </div>

      {/* --- HALAMAN 3: DOKUMENTASI & PENGESAHAN --- */}
      <div className="sheet bg-white shadow-2xl print:shadow-none w-full max-w-[210mm] min-h-[297mm] p-[25mm] relative mx-auto print:mt-0 flex flex-col justify-between">
        <div className="font-serif w-full h-full flex flex-col">

          {/* Header Internal */}
          <div className="border-b border-gray-300 pb-2 mb-6 text-right shrink-0">
            <p className="text-xs text-gray-400 italic">Lampiran: {analysis.judul_terpilih}</p>
          </div>

          {/* Section: Dokumentasi */}
          <div className="flex-1 flex flex-col">
            <h3 className="font-bold text-lg mb-4 border-b border-gray-200 pb-1">D. Dokumentasi Kegiatan</h3>

            <div className="flex-1 border border-gray-300 bg-gray-50 rounded-lg p-4 flex items-center justify-center overflow-hidden max-h-[140mm]">
              {image && (
                <img 
                  src={image} 
                  alt="Bukti Kegiatan" 
                  className="w-full h-full object-contain" 
                />
              )}
            </div>
            <p className="text-center text-sm text-gray-500 mt-2 italic">Gambar 1.1: {analysis.caption}</p>
          </div>

          {/* Footer / Signature with Image */}
          <div className="mt-12 flex justify-end shrink-0">
            <div className="text-center w-64">
              <p>{profile.kota}, {tanggalLaporan}</p>
              <p className="mt-1 mb-2">Guru Penyusun,</p>

              {/* Added Signature Image from Google Drive */}
              <div className="h-20 flex items-center justify-center my-2">
                <img 
                  src="https://drive.google.com/thumbnail?id=1gdxnC3M_VZLA--WQ5eEB66EJAO7dYm3o&sz=w500" 
                  alt="Tanda Tangan" 
                  className="h-full object-contain mix-blend-multiply" 
                />
              </div>

              <p className="font-bold underline text-lg">{profile.nama}</p>
              <p className="text-md">NIP. {profile.nip || "-"}</p>
            </div>
          </div>

        </div>
      </div>

    </div>
  );
};

import React, { useState, useRef } from 'react';
import { ProfileForm } from './components/ProfileForm';
import { ReportView } from './components/ReportView';
import { TeacherProfile, AnalysisResult, ReportData, CategoryId } from './types';
import { RHK_CATEGORIES } from './constants';
import { analyzeImageWithGemini } from './services/geminiService';

const App: React.FC = () => {
  // 1. Get Environment Key
  const ENV_API_KEY = (() => {
    try {
      // @ts-ignore
      if (typeof import.meta !== 'undefined' && import.meta.env) {
        // @ts-ignore
        if (import.meta.env.VITE_API_KEY) return import.meta.env.VITE_API_KEY;
        // @ts-ignore
        if (import.meta.env.API_KEY) return import.meta.env.API_KEY;
      }
      if (typeof process !== 'undefined' && process.env) {
        return process.env.REACT_APP_API_KEY || process.env.VITE_API_KEY || process.env.API_KEY;
      }
    } catch (e) {
      console.warn("Env error:", e);
    }
    return '';
  })();

  // 2. State for Custom User Key
  const [customApiKey, setCustomApiKey] = useState<string>('');

  // 3. Determine Effective Key (User Input > Env Var)
  const EFFECTIVE_API_KEY = customApiKey || ENV_API_KEY;

  const [profile, setProfile] = useState<TeacherProfile | null>(() => {
    if (typeof window !== 'undefined') {
      const savedProfile = localStorage.getItem('rhk_profile');
      return savedProfile ? JSON.parse(savedProfile) : null;
    }
    return null;
  });

  const [selectedCategoryId, setSelectedCategoryId] = useState<CategoryId | null>(null);
  const [reportData, setReportData] = useState<ReportData | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  // States for Student Assessment
  const [studentNames, setStudentNames] = useState<string>('');
  const [kelas, setKelas] = useState<string>('');

  const [userNote, setUserNote] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedQuarter, setSelectedQuarter] = useState<number>(1);

  const quarters = [
    { id: 1, label: 'Triwulan I', range: 'Januari - Maret' },
    { id: 2, label: 'Triwulan II', range: 'April - Juni' },
    { id: 3, label: 'Triwulan III', range: 'Juli - September' },
    { id: 4, label: 'Triwulan IV', range: 'Oktober - Desember' }
  ];

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSaveProfile = (newProfile: TeacherProfile) => {
    setProfile(newProfile);
    localStorage.setItem('rhk_profile', JSON.stringify(newProfile));
  };

  const handleChangeProfile = () => {
    if (confirm("Ubah data profil guru?")) {
      setProfile(null);
      setReportData(null);
      setSelectedCategoryId(null);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { 
        alert("Ukuran file terlalu besar (Maks 5MB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProcess = async () => {
    if (!EFFECTIVE_API_KEY) {
      setError("Konfigurasi Error: API Key tidak ditemukan. Masukkan API Key Anda.");
      return;
    }
    if (!profile || !selectedCategoryId) return;

    // Validation Logic
    const isPureAssessment = selectedCategoryId === 'STUDENT_ASSESSMENT';
    const isHybridMod = selectedCategoryId === 'RELIGIOUS_MODERATION';

    // 1. Validation for Image
    // Image is required for everything EXCEPT 'STUDENT_ASSESSMENT'
    if (!isPureAssessment && !selectedImage) {
      setError("Mohon upload foto kegiatan terlebih dahulu.");
      return;
    }

    // 2. Validation for Student Names
    // Required ONLY for pure assessment. For Hybrid, it's optional but good to have.
    if (isPureAssessment && !studentNames.trim()) {
      setError("Mohon isi daftar nama siswa.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const result: AnalysisResult = await analyzeImageWithGemini(
        EFFECTIVE_API_KEY, 
        selectedImage, // Can be null for assessment
        selectedCategoryId,
        userNote,
        studentNames,
        kelas
      );
      const categoryConfig = RHK_CATEGORIES.find(c => c.id === selectedCategoryId);

      const q = quarters.find(item => item.id === selectedQuarter);

      // Map quarter to the list of months in that quarter
      const quarterMonthsMap: Record<number, string[]> = {
        1: ['Januari', 'Februari', 'Maret'],
        2: ['April', 'Mei', 'Juni'],
        3: ['Juli', 'Agustus', 'September'],
        4: ['Oktober', 'November', 'Desember']
      };

      // Get possible months for the selected quarter and pick one randomly
      const possibleMonths = quarterMonthsMap[selectedQuarter];
      const randomMonth = possibleMonths[Math.floor(Math.random() * possibleMonths.length)];

      // Generate random border index (0 to 4)
      const randomBorderIndex = Math.floor(Math.random() * 5);

      const newReport: ReportData = {
        image: selectedImage,
        profile: profile,
        periode: `${q?.label} (${q?.range})`, 
        analysis: result,
        tanggalLaporan: `${randomMonth} 2025`,
        categoryLabel: categoryConfig ? categoryConfig.coverTitle : 'Laporan Kinerja',
        categoryId: selectedCategoryId,
        coverBorderIndex: randomBorderIndex
      };

      setReportData(newReport);
    } catch (err: any) {
      setError(err.message || "Terjadi kesalahan saat memproses data.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const resetAll = () => {
    setReportData(null);
    setSelectedImage(null);
    setUserNote(''); 
    setStudentNames('');
    setKelas('');
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleBackToMenu = () => {
    setSelectedCategoryId(null);
    setSelectedImage(null);
    setUserNote('');
    setStudentNames('');
    setKelas('');
    setError(null);
  };

  // Logic: Show setup screen ONLY if neither Env Key nor Custom Key is present AND user hasn't tried to input one yet.
  if (!EFFECTIVE_API_KEY && !error && !ENV_API_KEY) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-50">
        <div className="bg-white p-6 rounded-xl shadow-lg border-l-4 border-yellow-500 max-w-md w-full">
           <h2 className="text-xl font-bold mb-2">API Key Diperlukan</h2>
           <p className="text-slate-600 mb-4 text-sm">Aplikasi ini memerlukan Google Gemini API Key. Anda dapat menggunakan API Key gratis Anda sendiri.</p>
           <input 
              type="password" 
              placeholder="Tempel API Key disini..."
              className="w-full px-4 py-2 border border-slate-300 rounded mb-4"
              onChange={(e) => setCustomApiKey(e.target.value)}
           />
           <p className="text-xs text-slate-500 mb-4">
             Dapatkan key di <a href="https://aistudio.google.com/app/apikey" target="_blank" className="text-blue-600 underline">Google AI Studio</a>.
           </p>
           <button 
            disabled={!customApiKey}
            onClick={() => {}} 
            className="w-full bg-teal-600 text-white px-4 py-2 rounded disabled:opacity-50 hover:bg-teal-700 transition"
           >
             Mulai Aplikasi
           </button>
        </div>
      </div>
    );
  }

  if (reportData) {
    return <ReportView data={reportData} onReset={resetAll} />;
  }

  if (!profile) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <ProfileForm initialProfile={null} onSave={handleSaveProfile} />
      </div>
    );
  }

  if (!selectedCategoryId) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center pt-6 sm:pt-10 pb-6 px-4">
        <div className="w-full max-w-4xl">
           <header className="flex justify-between items-center mb-8">
              <div>
                <h1 className="text-2xl font-bold text-slate-800">Pilih Jenis Laporan</h1>
                <p className="text-slate-500">Silakan pilih kategori Rencana Hasil Kerja (RHK) yang akan dibuat.</p>
              </div>
              <button onClick={handleChangeProfile} className="text-sm text-teal-600 hover:underline font-semibold">
                Profil: {profile.nama}
              </button>
           </header>

           <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
              {RHK_CATEGORIES.map((cat) => (
                <button
                  key={cat.id}
                  onClick={() => setSelectedCategoryId(cat.id)}
                  className={`
                    relative overflow-hidden p-6 rounded-2xl shadow-sm hover:shadow-xl hover:scale-[1.02] border transition-all text-left group
                    ${cat.theme.bgGradient} border-slate-100 hover:border-transparent
                  `}
                >
                  {/* Background Shape Pattern */}
                  <div className="absolute top-0 right-0 -mt-4 -mr-4 w-32 h-32 opacity-10 pointer-events-none transform rotate-12 group-hover:scale-110 group-hover:opacity-20 transition-all duration-500">
                     <svg viewBox="0 0 24 24" fill="currentColor" className={cat.theme.primary}>
                        <path d={cat.theme.patternPath} />
                     </svg>
                  </div>

                  <div className={`
                    w-12 h-12 rounded-xl flex items-center justify-center mb-4 transition-colors z-10 relative
                    ${cat.theme.secondary} ${cat.theme.primary} group-hover:bg-white
                  `}>
