  title: string;
  type: 'paragraph' | 'list';
  content: string[]; // For paragraph, it's an array with 1 string. For list, multiple strings.
}

export interface StudentGrade {
  nama: string;
  predikat: 'SB' | 'B' | 'C' | 'K';
  deskripsi: string;
}

