import { TeacherProfile, AnalysisResult, ReportData, CategoryId } from './types';
import { RHK_CATEGORIES } from './constants';
import { analyzeImageWithGemini } from './services/geminiService';

const App: React.FC = () => {
  // 1. Get Environment Key
  const ENV_API_KEY = (() => {
    try {
      // @ts-ignore
      if (typeof import.meta !== 'undefined' && import.meta.env) {
        // @ts-ignore
        if (import.meta.env.VITE_API_KEY) return import.meta.env.VITE_API_KEY;
        // @ts-ignore
        if (import.meta.env.API_KEY) return import.meta.env.API_KEY;
      }
      if (typeof process !== 'undefined' && process.env) {
        return process.env.REACT_APP_API_KEY || process.env.VITE_API_KEY || process.env.API_KEY;
      }
    } catch (e) {
      console.warn("Env error:", e);
    }
    return '';
  })();

  // 2. State for Custom User Key
  const [customApiKey, setCustomApiKey] = useState<string>('');

  // 3. Determine Effective Key (User Input > Env Var)
  const EFFECTIVE_API_KEY = customApiKey || ENV_API_KEY;

  const [profile, setProfile] = useState<TeacherProfile | null>(() => {
    if (typeof window !== 'undefined') {
      const savedProfile = localStorage.getItem('rhk_profile');
      return savedProfile ? JSON.parse(savedProfile) : null;
    }
    return null;
  });

  const [selectedCategoryId, setSelectedCategoryId] = useState<CategoryId | null>(null);
  const [reportData, setReportData] = useState<ReportData | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  // States for Student Assessment (Hybrid Mode)
  const [studentNames, setStudentNames] = useState<string>('');
  const [kelas, setKelas] = useState<string>('');

  const [userNote, setUserNote] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedQuarter, setSelectedQuarter] = useState<number>(1);

  const quarters = [
    { id: 1, label: 'Triwulan I', range: 'Januari - Maret' },
    { id: 2, label: 'Triwulan II', range: 'April - Juni' },
    { id: 3, label: 'Triwulan III', range: 'Juli - September' },
    { id: 4, label: 'Triwulan IV', range: 'Oktober - Desember' }
  ];

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSaveProfile = (newProfile: TeacherProfile) => {
    setProfile(newProfile);
    localStorage.setItem('rhk_profile', JSON.stringify(newProfile));
  };

  const handleChangeProfile = () => {
    if (confirm("Ubah data profil guru?")) {
      setProfile(null);
      setReportData(null);
      setSelectedCategoryId(null);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { 
        alert("Ukuran file terlalu besar (Maks 5MB)");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProcess = async () => {
    if (!EFFECTIVE_API_KEY) {
      setError("Konfigurasi Error: API Key tidak ditemukan. Masukkan API Key Anda.");
      return;
    }
    if (!profile || !selectedCategoryId) return;

    // 1. Validation for Image (Always Required)
    if (!selectedImage) {
      setError("Mohon upload foto kegiatan terlebih dahulu.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const result: AnalysisResult = await analyzeImageWithGemini(
        EFFECTIVE_API_KEY, 
        selectedImage,
        selectedCategoryId,
        userNote,
        studentNames,
        kelas
      );
      const categoryConfig = RHK_CATEGORIES.find(c => c.id === selectedCategoryId);

      const q = quarters.find(item => item.id === selectedQuarter);

      // Map quarter to the list of months in that quarter
      const quarterMonthsMap: Record<number, string[]> = {
        1: ['Januari', 'Februari', 'Maret'],
        2: ['April', 'Mei', 'Juni'],
        3: ['Juli', 'Agustus', 'September'],
        4: ['Oktober', 'November', 'Desember']
      };

      // Get possible months for the selected quarter and pick one randomly
      const possibleMonths = quarterMonthsMap[selectedQuarter];
      const randomMonth = possibleMonths[Math.floor(Math.random() * possibleMonths.length)];

      // Generate random border index (0 to 4)
      const randomBorderIndex = Math.floor(Math.random() * 5);

      const newReport: ReportData = {
        image: selectedImage,
        profile: profile,
        periode: `${q?.label} (${q?.range})`, 
        analysis: result,
        tanggalLaporan: `${randomMonth} 2025`,
        categoryLabel: categoryConfig ? categoryConfig.coverTitle : 'Laporan Kinerja',
        categoryId: selectedCategoryId,
        coverBorderIndex: randomBorderIndex
      };

      setReportData(newReport);
    } catch (err: any) {
      setError(err.message || "Terjadi kesalahan saat memproses data.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const resetAll = () => {
    setReportData(null);
    setSelectedImage(null);
    setUserNote(''); 
    setStudentNames('');
    setKelas('');
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleBackToMenu = () => {
    setSelectedCategoryId(null);
    setSelectedImage(null);
    setUserNote('');
    setStudentNames('');
    setKelas('');
    setError(null);
  };

  // Logic: Show setup screen ONLY if neither Env Key nor Custom Key is present AND user hasn't tried to input one yet.
  if (!EFFECTIVE_API_KEY && !error && !ENV_API_KEY) {
    return (
      <div className="min-h-screen flex items-center justify-center p-6 bg-slate-50">
        <div className="bg-white p-6 rounded-xl shadow-lg border-l-4 border-yellow-500 max-w-md w-full">
           <h2 className="text-xl font-bold mb-2">API Key Diperlukan</h2>
           <p className="text-slate-600 mb-4 text-sm">Aplikasi ini memerlukan Google Gemini API Key. Anda dapat menggunakan API Key gratis Anda sendiri.</p>
           <input 
              type="password" 
              placeholder="Tempel API Key disini..."
              className="w-full px-4 py-2 border border-slate-300 rounded mb-4"
              onChange={(e) => setCustomApiKey(e.target.value)}
           />
           <p className="text-xs text-slate-500 mb-4">
             Dapatkan key di <a href="https://aistudio.google.com/app/apikey" target="_blank" className="text-blue-600 underline">Google AI Studio</a>.
           </p>
           <button 
            disabled={!customApiKey}
            onClick={() => {}} 
            className="w-full bg-teal-600 text-white px-4 py-2 rounded disabled:opacity-50 hover:bg-teal-700 transition"
           >
             Mulai Aplikasi
           </button>
        </div>
      </div>
    );
  }

  if (reportData) {
    return <ReportView data={reportData} onReset={resetAll} />;
  }

  if (!profile) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <ProfileForm initialProfile={null} onSave={handleSaveProfile} />
      </div>
    );
  }

  if (!selectedCategoryId) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center pt-6 sm:pt-10 pb-6 px-4">
        <div className="w-full max-w-4xl">
           <header className="flex justify-between items-center mb-8">
              <div>
                <h1 className="text-2xl font-bold text-slate-800">Pilih Jenis Laporan</h1>
                <p className="text-slate-500">Silakan pilih kategori Rencana Hasil Kerja (RHK) yang akan dibuat.</p>
              </div>
              <button onClick={handleChangeProfile} className="text-sm text-teal-600 hover:underline font-semibold">
                Profil: {profile.nama}
              </button>
           </header>

           <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
              {RHK_CATEGORIES.map((cat) => (
                <button
                  key={cat.id}
                  onClick={() => setSelectedCategoryId(cat.id)}
                  className={`
                    relative overflow-hidden p-6 rounded-2xl shadow-sm hover:shadow-xl hover:scale-[1.02] border transition-all text-left group
                    ${cat.theme.bgGradient} border-slate-100 hover:border-transparent
                  `}
                >
                  {/* Background Shape Pattern */}
                  <div className="absolute top-0 right-0 -mt-4 -mr-4 w-32 h-32 opacity-10 pointer-events-none transform rotate-12 group-hover:scale-110 group-hover:opacity-20 transition-all duration-500">
                     <svg viewBox="0 0 24 24" fill="currentColor" className={cat.theme.primary}>
                        <path d={cat.theme.patternPath} />
                     </svg>
                  </div>

                  <div className={`
                    w-12 h-12 rounded-xl flex items-center justify-center mb-4 transition-colors z-10 relative
                    ${cat.theme.secondary} ${cat.theme.primary} group-hover:bg-white
                  `}>
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={cat.icon} />
                    </svg>
                  </div>

                  <div className="relative z-10">
                    <h3 className={`text-lg font-bold mb-1 ${cat.theme.primary}`}>{cat.title}</h3>
                    <p className="text-sm text-slate-600 leading-relaxed opacity-90 line-clamp-2">{cat.description}</p>
                  </div>
                </button>
              ))}
           </div>
        </div>
      </div>
    );
  }

  const currentCategory = RHK_CATEGORIES.find(c => c.id === selectedCategoryId);
  // Default fallback if not found
  const headerColor = currentCategory?.theme.headerColor || 'bg-teal-700';

  // Logic to determine what inputs to show. 
  // Now includes TEACHING, RELIGIOUS_MODERATION, and COMPETITION.
  const isHybridMod = selectedCategoryId === 'RELIGIOUS_MODERATION' || selectedCategoryId === 'TEACHING' || selectedCategoryId === 'COMPETITION';

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center pt-6 sm:pt-10 pb-6 px-4">
      <div className="w-full max-w-lg bg-white rounded-3xl shadow-xl overflow-hidden relative">

        <header className={`${headerColor} p-6 text-white transition-colors duration-300 relative overflow-hidden`}>
          {/* Decorative Pattern in Header */}
          <div className="absolute -right-6 -top-6 w-32 h-32 opacity-20 pointer-events-none">
             <svg viewBox="0 0 24 24" fill="currentColor">
                <path d={currentCategory?.theme.patternPath || ''} />
             </svg>
          </div>

          <button 
            onClick={handleBackToMenu}
            className="flex items-center gap-1 text-white/80 text-sm mb-4 hover:text-white transition relative z-10"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"></path></svg>
            Kembali ke Menu
          </button>
          <div className="flex items-start gap-4 relative z-10">
             <div className="p-3 bg-white/20 rounded-xl backdrop-blur-sm">
               <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={currentCategory?.icon || ''} />
               </svg>
             </div>
             <div>
               <h1 className="text-xl font-bold">{currentCategory?.title}</h1>
               <p className="text-white/80 text-xs mt-1">{profile.nama}</p>
             </div>
          </div>
        </header>

        <div className="p-6 flex flex-col gap-6">
          <div className="flex flex-col gap-3">
            <label className="text-sm font-bold text-slate-700 uppercase tracking-wide">Pilih Periode Triwulan</label>
            <div className="grid grid-cols-2 gap-2">
              {quarters.map((q) => (
                <button
                  key={q.id}
                  onClick={() => setSelectedQuarter(q.id)}
                  className={`p-3 rounded-xl border-2 text-left transition-all ${
                    selectedQuarter === q.id 
                    ? `border-${currentCategory?.theme.primary.split('-')[1] || 'teal'}-600 bg-white text-${currentCategory?.theme.primary.split('-')[1] || 'teal'}-800 shadow-sm`
                    : 'border-slate-100 hover:border-slate-300 text-slate-600'
                  }`}
                  style={selectedQuarter === q.id ? { borderColor: 'currentColor' } : {}}
                >
                  <div className="text-sm font-bold">{q.label}</div>
                  <div className="text-[10px] opacity-70">{q.range}</div>
                </button>
              ))}
            </div>
          </div>

          {/* --- IMAGE UPLOAD SECTION (Required for All) --- */}
          <div 
            onClick={() => !isAnalyzing && fileInputRef.current?.click()}
            className={`
              relative group cursor-pointer rounded-3xl border-2 border-dashed transition-all duration-300 overflow-hidden aspect-video flex flex-col items-center justify-center text-center p-6
              ${selectedImage ? 'border-transparent bg-slate-50' : 'border-slate-300 hover:border-current hover:bg-slate-50'}
              ${isAnalyzing ? 'opacity-50 cursor-not-allowed' : ''}
              ${currentCategory?.theme.accent || 'text-teal-600'}
            `}
          >
            {selectedImage ? (
              <>
                <img src={selectedImage} alt="Preview" className="absolute inset-0 w-full h-full object-contain z-0 bg-black/5" />
                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center z-10 text-white font-medium">
                  Ganti Foto / Sertifikat
                </div>
              </>
            ) : (
              <>
                <div className={`p-4 rounded-full mb-3 group-hover:scale-110 transition-transform ${currentCategory?.theme.secondary || 'bg-teal-50'}`}>
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                </div>
                <h3 className="font-bold text-slate-700 text-lg">Upload Foto / Sertifikat</h3>
                <p className="text-sm text-slate-400">Bukti kegiatan atau sertifikat lomba</p>
              </>
            )}
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileChange} 
              accept="image/*" 
              className="hidden" 
              disabled={isAnalyzing}
            />
          </div>

          {/* --- STUDENT INPUT SECTION (Religious Moderation & Character Education & Competition) --- */}
          {isHybridMod && (
            <div className="flex flex-col gap-4 bg-slate-50 p-4 rounded-xl border border-slate-100">
               <div className="flex items-center gap-2 text-xs font-semibold text-amber-700 mb-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                  <span>Opsional: Isi data {selectedCategoryId === 'COMPETITION' ? 'peserta lomba' : 'siswa'} untuk generate tabel {selectedCategoryId === 'COMPETITION' ? 'prestasi/partisipasi' : 'penilaian'}.</span>
               </div>
              <div>
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide mb-2 block">
                  Daftar Nama {selectedCategoryId === 'COMPETITION' ? 'Peserta' : 'Siswa'} (Opsional)
                </label>
                <textarea
                  value={studentNames}
                  onChange={(e) => setStudentNames(e.target.value)}
                  placeholder="Paste nama dari Excel disini...&#10;Contoh:&#10;Ahmad Dahlan&#10;Siti Walidah"
                  className="w-full h-32 px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-amber-500 focus:ring-0 outline-none transition-all text-slate-700 bg-white placeholder-slate-400 text-sm"
                  disabled={isAnalyzing}
                />
              </div>
              <div>
                 <label className="text-sm font-bold text-slate-700 uppercase tracking-wide mb-2 block">Kelas / Rombel (Opsional)</label>
                 <input
                  type="text"
                  value={kelas}
                  onChange={(e) => setKelas(e.target.value)}
                  placeholder="Contoh: VII A"
                  className="w-full px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-amber-500 focus:ring-0 outline-none transition-all text-slate-700 bg-white placeholder-slate-400"
                  disabled={isAnalyzing}
                />
              </div>
            </div>
          )}

          {/* --- USER NOTE SECTION --- */}
          <div className="flex flex-col gap-2">
            <label className="text-sm font-bold text-slate-700 uppercase tracking-wide">
              Keterangan / Judul Spesifik (Opsional)
            </label>
            <input
              type="text"
              value={userNote}
              onChange={(e) => setUserNote(e.target.value)}
              placeholder="Contoh: Kegiatan Diskusi Kelompok"
              className="w-full px-4 py-3 rounded-xl border-2 border-slate-100 focus:border-current focus:ring-0 outline-none transition-all text-slate-700 bg-slate-50 placeholder-slate-400"
              style={{ color: 'inherit' }}
              disabled={isAnalyzing}
            />
            <p className="text-xs text-slate-400">
              Bantu AI mengenali kegiatan dengan memberikan judul atau deskripsi singkat.
            </p>
          </div>

          {error && (
            <div className="bg-red-50 border border-red-100 p-4 rounded-xl text-sm flex flex-col gap-3 animate-fade-in">
              <div className="flex items-start gap-3 text-red-600">
                <svg className="w-5 h-5 flex-shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                <span>{error}</span>
              </div>

              <div className="bg-white/60 p-3 rounded-lg border border-red-200 mt-1">
                <label className="block text-xs font-bold text-red-800 mb-1 uppercase tracking-wider">
                  Gunakan API Key Pribadi (Sementara)
                </label>
                <div className="flex gap-2">
                  <input 
                    type="password"
                    value={customApiKey}
                    onChange={(e) => setCustomApiKey(e.target.value)}
                    placeholder="Paste Gemini API Key disini..."
                    className="flex-1 text-sm px-3 py-2 border border-red-200 rounded focus:border-red-500 outline-none"
                  />
                </div>
                <p className="text-[10px] text-red-500 mt-2">
                   Jika limit aplikasi habis, Anda dapat menggunakan Free API Key milik sendiri. <a href="https://aistudio.google.com/app/apikey" target="_blank" className="underline font-bold hover:text-red-700">Buat Key Disini</a>.
                </p>
              </div>
            </div>
          )}

          <button
            onClick={handleProcess}
            disabled={isAnalyzing}
            className={`
              w-full py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-3 transition-all transform active:scale-[0.98]
              ${isAnalyzing 
                ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none' 
                : `${headerColor} text-white hover:brightness-110 shadow-teal-900/10`
              }
            `}
          >
            {isAnalyzing ? (
              <>
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                <span className="animate-pulse">Sedang Menganalisis...</span>
              </>
            ) : (
              <>
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                {customApiKey ? 'Coba Lagi dengan Key Baru' : 'Proses Data AI'}
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { RHK_CATEGORIES } from "../constants";
import { AnalysisResult, CategoryId } from "../types";

// Helper for robust error parsing
const handleGeminiError = (error: any, contextPrefix: string): never => {
  console.error(`Gemini Error [${contextPrefix}]:`, error);

  let finalMessage = "";
  const errString = error.toString().toLowerCase();
  const errMessage = (error.message || "").toLowerCase();

  // Check strict codes first
  const isQuota = errString.includes("429") || errMessage.includes("quota") || errMessage.includes("limit") || errMessage.includes("resource_exhausted");
  const isAuth = errString.includes("401") || errString.includes("403") || errMessage.includes("key") || errMessage.includes("permission");
  const isOverload = errString.includes("503") || errMessage.includes("overloaded");

  if (isQuota) {
    finalMessage = "Kuota API Harian/Menit Telah Habis. Mohon gunakan API Key Google Gemini milik Anda sendiri (Gratis di aistudio.google.com).";
  } else if (isAuth) {
    finalMessage = "API Key tidak valid atau tidak memiliki izin akses.";
  } else if (isOverload) {
    finalMessage = "Server Google AI sedang sibuk. Silakan coba sesaat lagi.";
  } else {
    // Clean up generic error messages
    const rawMsg = error.message || "Terjadi kesalahan tidak terduga.";
    // Remove JSON garbage if present in message
    const cleanMsg = rawMsg.replace(/\{.*"error".*\}/g, "Detail error teknis (lihat console).");
    finalMessage = `${contextPrefix}: ${cleanMsg}`;
  }

  throw new Error(finalMessage);
};

export const analyzeImageWithGemini = async (
  apiKey: string,
  base64Image: string | null,
  categoryId: CategoryId,
  userNote?: string, // Used as 'Materi/Bab' for assessment
  studentNames?: string, // New param for list of students
  kelas?: string // New param for class
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const model = "gemini-2.5-flash"; 

  // Find the selected category configuration
  const selectedCategory = RHK_CATEGORIES.find(c => c.id === categoryId);
  if (!selectedCategory) throw new Error("Kategori RHK tidak valid");

  const rhkListString = selectedCategory.rhkList.join("\n- ");

  // --- IMAGE ANALYSIS (REQUIRED) ---
  if (!base64Image) throw new Error("Gambar diperlukan untuk analisis.");

  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpg|jpeg|webp);base64,/, "");

  // Define structure instructions based on category
  let structureInstruction = "";
  let additionalInstruction = "";

  if (categoryId === 'DIGITAL') {
    structureInstruction = `
      Buat struktur laporan dengan sections berikut:
      1. Title: "Analisis Kebutuhan & Masalah" (Type: paragraph) -> Jelaskan masalah pembelajaran yang butuh solusi digital.
      2. Title: "Implementasi Teknologi" (Type: paragraph) -> Deskripsikan cara penggunaan alat/aplikasi dalam kegiatan.
      3. Title: "Spesifikasi Alat & Aplikasi" (Type: list) -> Sebutkan nama aplikasi, hardware, atau platform yang digunakan.
      4. Title: "Dampak & Efektivitas" (Type: list) -> Poin-poin peningkatan hasil belajar.
    `;
  } else if (categoryId === 'CHILD_FRIENDLY') {
    structureInstruction = `
      Buat struktur laporan dengan sections berikut:
      1. Title: "Situasi & Kondisi Awal" (Type: paragraph) -> Konteks interaksi di kelas.
      2. Title: "Bentuk Layanan Ramah Anak" (Type: paragraph) -> Deskripsi pendekatan humanis, 5S, atau pencegahan bullying.
      3. Title: "Prinsip Hak Anak" (Type: list) -> Poin hak anak yang dipenuhi.
      4. Title: "Respon Siswa" (Type: list) -> Poin respon emosional siswa.
    `;
  } else if (categoryId === 'RELIGIOUS_MODERATION') {
    structureInstruction = `
      Buat struktur laporan dengan sections berikut:
      1. Title: "Latar Belakang Kegiatan" (Type: paragraph) -> Konteks keberagaman atau materi ajar dalam foto.
      2. Title: "Penguatan Nilai Moderasi" (Type: paragraph) -> Narasi penanaman nilai yang terjadi.
      3. Title: "Indikator Sikap Moderat" (Type: list) -> Poin sikap yang muncul dalam kegiatan.
    `;
  } else if (categoryId === 'TEACHING') {
    // This is now CHARACTER EDUCATION
    structureInstruction = `
      Buat struktur laporan dengan sections berikut:
      1. Title: "Nilai Karakter & Pembiasaan" (Type: paragraph) -> Jelaskan nilai karakter utama (Jujur, Disiplin, Gotong Royong, dll) yang dibangun dalam kegiatan ini.
      2. Title: "Deskripsi Pelaksanaan" (Type: paragraph) -> Gambarkan bagaimana proses penanaman karakter dilakukan.
      3. Title: "Refleksi & Dampak" (Type: list) -> Poin perubahan perilaku positif yang diharapkan/terlihat pada siswa.
    `;
  } else if (categoryId === 'COMPETITION') {
    structureInstruction = `
      Buat struktur laporan dengan sections berikut:
      1. Title: "Identitas Kompetisi" (Type: paragraph) -> Jelaskan Nama Lomba, Tingkat (Sekolah/Kab/Prov/Nasional), dan Penyelenggara berdasarkan sertifikat/foto.
      2. Title: "Persiapan & Pelaksanaan" (Type: paragraph) -> Deskripsikan proses pembimbingan atau keikutsertaan dalam lomba tersebut.
      3. Title: "Hasil & Prestasi" (Type: list) -> Poin capaian, penghargaan, atau pengalaman yang didapat.
    `;
  }

  // HYBRID LOGIC: If student names are provided, ask to generate grades.
  // Applies to Religious Moderation, Teaching (Character Education), and Competition
  if (studentNames && (categoryId === 'RELIGIOUS_MODERATION' || categoryId === 'TEACHING' || categoryId === 'COMPETITION')) {

    let focusValue = "";
    let gradingInstruction = "";

    if (categoryId === 'COMPETITION') {
      focusValue = "Kategori/Cabang Lomba";
      gradingInstruction = "Untuk 'predikat', gunakan kode berikut: 'SB' = Juara/Terbaik, 'B' = Finalis/Baik, 'C' = Peserta. Di 'deskripsi', tuliskan capaian spesifik (Juara 1, Harapan 2, Peserta Aktif, dll).";
    } else {
      focusValue = categoryId === 'RELIGIOUS_MODERATION' 
          ? "Prinsip Moderasi Beragama (Tasamuh, Tawazun, dll)" 
          : "Nilai Karakter Utama (Disiplin, Tanggung Jawab, Integritas, dll)";
      gradingInstruction = "Untuk setiap siswa, berikan nilai (SB/B/C/K) dan deskripsi sikap yang relevan dengan nilai karakter/moderasi yang kamu temukan di foto.";
    }

    additionalInstruction = `
      TUGAS TAMBAHAN (Wajib karena ada daftar siswa):
      1. Analisis visual foto/sertifikat untuk menentukan SATU ${focusValue} yang paling dominan/relevan. Isi ke field 'prinsipModerasi'.
      2. Gunakan daftar nama siswa berikut:
         ${studentNames}
      3. Buat objek 'studentGrades'. ${gradingInstruction}
      4. Field 'kelas' diisi dengan: "${kelas || 'Umum'}".
    `;
  }

  const prompt = `
    Saya mengirimkan foto kegiatan guru. Konteks: ${selectedCategory.title}.
    ${userNote ? `\nCATATAN KHUSUS PENGGUNA: "${userNote}"` : ''}

    Tugas Utama:
    1. Identifikasi visual foto.
    2. Pilih SATU Judul RHK yang paling cocok dari daftar:
    ${rhkListString}
    3. Tentukan jenis kegiatan (Intrakurikuler/Kokurikuler/Ekstrakurikuler).
    4. Isi field 'caption': Deskripsi singkat dan formal (1 kalimat) tentang foto.
    5. ${structureInstruction}

    ${additionalInstruction}

    Gunakan Bahasa Indonesia formal untuk laporan resmi dinas.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: cleanBase64 } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            judul_terpilih: { type: Type.STRING },
            jenis_kegiatan: { type: Type.STRING, enum: ["Intrakurikuler", "Kokurikuler", "Ekstrakurikuler"] },
            caption: { type: Type.STRING },
            // Optional fields for hybrid mode
            prinsipModerasi: { type: Type.STRING },
            kelas: { type: Type.STRING },
            studentGrades: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    nama: { type: Type.STRING },
                    predikat: { type: Type.STRING, enum: ["SB", "B", "C", "K"] },
                    deskripsi: { type: Type.STRING }
                  },
                  required: ["nama", "predikat", "deskripsi"]
                }
            },
            sections: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  type: { type: Type.STRING, enum: ["paragraph", "list"] },
                  content: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["title", "type", "content"]
              }
            }
          },
          required: ["judul_terpilih", "jenis_kegiatan", "caption", "sections"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const result = JSON.parse(text) as AnalysisResult;
    return result;

  } catch (error: any) {
    handleGeminiError(error, "Gagal menganalisis foto");
  }
};

